blocks.body:
{
    "level": "A1–A2",
    "intro": "У цій темі ти вивчиш <strong>чотири види речень</strong> в англійській мові: стверджувальні, заперечні, питальні та наказові — їхню структуру та особливості.",
    "rules": [
        {
            "label": "Twierdząca",
            "color": "emerald",
            "text": "<strong>Twierdząca</strong> — podaj fakt:",
            "example": "Ona czyta książki."
        },
        {
            "label": "Przecząca",
            "color": "rose",
            "text": "<strong>Przecząca</strong> — zaprzeczaj akcja:",
            "example": "Ona nie czyta książek: książka!"
        },
        {
            "label": "Interrogative",
            "color": "blue",
            "text": "<strong>Питальні</strong> — ставлять запитання:",
            "example": "Does she read books?"
        },
        {
            "label": "Imperative",
            "color": "amber",
            "text": "<strong>Наказові</strong> — виражають наказ або прохання:",
            "example": "Read this book!"
        }
    ]
}

{
    "title": "1. Przegląd czterech typów zdań tutaj.)",
    "intro": "Англійські речення поділяються на чотири типи за метою висловлювання:",
    "items": [
        {
            "label": "Affirmative",
            "title": "Стверджувальне",
            "subtitle": "Констатує факт або дію (She works here.)"
        },
        {
            "label": "Przeczące",
            "title": "Przeczące",
            "subtitle": "Zaprzecza faktowi lub działaniu (Ona nie działa tutaj.)"
        },
        {
            "label": "Pytające",
            "title": "Pytające",
            "subtitle": "Zadaj pytanie (Czy ona tu pracuje?)"
        },
        {
            "label": "Rozkazujące",
            "title": "Rozkazujące",
            "subtitle": "Wyraża rozkaz, prośbę, radę (Pracuj ciężej!)"
        }
    ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Zdanie twierdzące stwierdza fakt. Struktura: <strong>Podmiot + Czasownik + Dopełnienie</strong>.",
            "examples": [
                {
                    "en": "Lubię kawę.",
                    "ua": "Uwielbiam kawę."
                },
                {
                    "en": "Ona pracuje w szpitalu.",
                    "ua": "Pracuje w szpitalu."
                },
                {
                    "en": "Mają dwójkę dzieci.",
                    "ua": " dzieci."
                }
            ]
        },
        {
            "label": "Z czasownikiem TO BE",
            "color": "sky",
            "description": "Z czasownikiem <strong>być</strong> strukturą: <strong>Podmiot + am/is/are + Uzupełnienie</strong>.",
            "examples": [
                {
                    "en": "Jestem studentka.",
                    "ua": "Jestem studentką."
                },
                {
                    "en": "Ona jest szczęśliwa: wschód.",
                    "ua": "Вона щаслива."
                },
                {
                    "en": "They are at home.",
                    "ua": "Вони вдома."
                }
            ]
        },
        {
            "label": "Пунктуація",
            "color": "amber",
            "description": "Стверджувальне речення закінчується <strong>крапкою (.)</strong>",
            "examples": [
                {
                    "en": "The sun rises in the east.",
                    "ua": "Słońce wschodzi na wschodzie."
                }
            ]
        }
    ]
}

{
    "title": "3. Zdania przeczące – zdania przeczące",
    "sections": [
        {
            "label": "Z czasownikiem pomocniczym",
            "color": "emerald",
            "description": "Aby zanegować, dodaj <strong>do/does/did + not</strong> przed głównym czasownikiem.",
            "examples": [
                {
                    "en": "Nie lubię kawy.",
                    "ua": "Nie lubię kawa."
                },
                {
                    "en": "Ona tu nie pracuje: <strong>jestem/jest/jestem + nie</strong>.",
                    "ua": "Вона тут не працює."
                },
                {
                    "en": "They did not come yesterday.",
                    "ua": "Вони не прийшли вчора."
                }
            ]
        },
        {
            "label": "З дієсловом TO BE",
            "color": "sky",
            "description": "З дієсловом <strong>to be</strong> додаємо <strong>not</strong> після нього: <strong>am/is/are + not</strong>.",
            "examples": [
                {
                    "en": "I am not tired.",
                    "ua": "Я не втомлений."
                },
                {
                    "en": "She is not at home.",
                    "ua": "Її немає вдома."
                },
                {
                    "en": "They are not ready.",
                    "ua": "Вони не готові."
                }
            ]
        },
        {
            "label": "Скорочені форми",
            "color": "amber",
            "description": "W języku potocznym często używane są <strong>skróty</strong>.",
            "examples": [
                {
                    "en": "nie = nie",
                    "ua": "Nie podoba mi się to."
                },
                {
                    "en": "nie = nie",
                    "ua": "Ona nie wie."
                },
                {
                    "en": "nie jest = nie jest",
                    "ua": "nie ma go tutaj."
                },
                {
                    "en": "nie ma = nie jest",
                    "ua": "nie przyjdą."
                }
            ]
        }
    ]
}

{
    "title": "4. Zdania pytające - Zdania pytające",
    "sections": [
        {
            "label": "Pytania tak/nie",
            "color": "emerald",
            "description": "Pytania ogólne (odpowiedź Tak/Nie). Struktura: Do/Does/Did + Podmiot + Czasownik? wczoraj?",
            "examples": [
                {
                    "en": "Do you like coffee?",
                    "ua": "Ти любиш каву?"
                },
                {
                    "en": "Does she work here?",
                    "ua": "Вона тут працює?"
                },
                {
                    "en": "Did they come yesterday?",
                    "ua": "Przyszli wczoraj?"
                }
            ]
        },
        {
            "label": "Pytanie z TO BE",
            "color": "sky",
            "description": "W przypadku czasownika <strong>być</strong> na pierwszym miejscu pojawia się: <strong>Am/Is/Are + Temat?</strong>",
            "examples": [
                {
                    "en": "Czy jesteś gotowy? gotowa?",
                    "ua": "Ти готовий?"
                },
                {
                    "en": "Czy ona jest lekarzem?",
                    "ua": "Jest lekarzem?"
                },
                {
                    "en": "Byli na imprezie?",
                    "ua": "Byli na imprezie impreza?"
                }
            ]
        },
        {
            "label": "Pytania o pytanie",
            "color": "amber",
            "description": "Pytania specjalne zawierające słowa pytające: <strong>Co, Gdzie, Kiedy, Dlaczego, Kto, Jak</strong>.",
            "examples": [
                {
                    "en": "Co robisz?",
                    "ua": "Co robisz co robi?"
                },
                {
                    "en": "Gdzie ona mieszka?",
                    "ua": "Gdzie ona mieszka?"
                },
                {
                    "en": " Dlaczego się spóźniłeś? Zdania rozkazujące - Zdania rozkazujące",
                    "ua": "Чому ти запізнився?"
                },
                {
                    "en": "How did they get there?",
                    "ua": "Як вони туди дістались?"
                }
            ],
            "note": "Питальне речення закінчується <strong>знаком питання (?)</strong>."
        }
    ]
}

{
    "title": "5. Imperative Sentences — Наказові речення",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Zdanie rozkazujące wyraża polecenie, prośbę lub radę. Rozpoczyna się od <strong>czasownika w formie podstawowej</strong>, bez podmiotu.",
            "examples": [
                {
                    "en": "Otwórz drzwi.",
                    "ua": "Otwórz drzwi."
                },
                {
                    "en": "Chodź tutaj.",
                    "ua": "Chodź tutaj."
                },
                {
                    "en": "Bądź cicho.",
                    "ua": "Zachowuj się cicho."
                }
            ]
        },
        {
            "label": "Forma przecząca",
            "color": "sky",
            "description": "W przypadku polecenia przeczącego używamy <strong>Nie (nie) + czasownik</strong>.",
            "examples": [
                {
                    "en": "Nie dotykaj tego!",
                    "ua": "Nie dotykaj to!"
                },
                {
                    "en": "Nie spóźnij się.",
                    "ua": "Nie spóźnij się."
                },
                {
                    "en": "Nie zapomnij kluczy.",
                    "ua": "Nie zapomnij kluczy."
                }
            ]
        },
        {
            "label": "Uprzejmy formularze",
            "color": "amber",
            "description": "Aby zachować grzeczność, dodaj <strong>proszę</strong> lub użyj <strong>Let's</strong>, aby uzyskać sugestie.",
            "examples": [
                {
                    "en": "Proszę usiąść.",
                    "ua": "Proszę usiąść."
                },
                {
                    "en": "Prosimy o cierpliwość.",
                    "ua": "Proszę być pacjent."
                },
                {
                    "en": "Chodźmy do kina.",
                    "ua": "Chodźmy do kina."
                },
                {
                    "en": "Zacznijmy spotkanie.",
                    "ua": "Zacznijmy spotkanie."
                }
            ],
            "note": "Zdanie rozkazujące może zakończyć się wyrazem rozkazującym <strong>kropka (.)</strong> lub <strong>wykrzyknik (!)</strong>."
        }
    ]
}

{
    "title": "6. Tabela porównawcza struktur",
    "intro": "Struktury czterech typów zdań:",
    "rows": [
        {
            "en": "Twierdzące",
            "ua": "Twierdzące",
            "note": "S + V + O → Ona czyta książki."
        },
        {
            "en": "Negatywny",
            "ua": "Negatywny",
            "note": "S + robi/robi + nie + V → Ona nie czytaj."
        },
        {
            "en": "Zapytanie",
            "ua": "Zapytanie",
            "note": "Czy/Robi + S + V? → Czy on czyta? (zrób/robi/zrobił)!"
        },
        {
            "en": "Imperative",
            "ua": "Наказове",
            "note": "V + O → Read this book!"
        }
    ],
    "warning": "📌 Запамʼятай: в питаннях і запереченнях потрібні <strong>допоміжні дієслова</strong> (do/does/did)!"
}

{
    "title": "7. Interpunkcja różnych typów zdań",
    "intro": "Każdy rodzaj zdania ma swój własny znak interpunkcyjny:",
    "rows": [
        {
            "en": "Twierdzące",
            "ua": "Twierdzące",
            "note": "Kropka (.) — Ona jest nauczyciel."
        },
        {
            "en": "Negatywny",
            "ua": "Negatywny",
            "note": "Kropka (.) — Ona nie jest nauczyciel."
        },
        {
            "en": "Pytające",
            "ua": "Pytające",
            "note": "Znak zapytania (?) — Czy ona jest nauczyciel?"
        },
        {
            "en": "Rozkaz",
            "ua": "Polecenie",
            "note": "Kropka (.) lub wykrzyknik (!) — Cicho! / Bądź cicho."
        }
    ]
}

{
    "title": "8. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie czasownika pomocniczego w przeczeniach.",
            "wrong": "Ona nie lubi kawy.",
            "right": "​​​​ <span class="font-mono">Nie lubi kawa.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Pominięcie czasownika pomocniczego w pytaniach.",
            "wrong": "Lubisz kawę?",
            "right": "​​​​​​​​ kawa?</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Закінчення -s після does.",
            "wrong": "Does she likes coffee?",
            "right": "✅ <span class="font-mono">Does she like coffee?</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Temat w zdaniu rozkazującym.",
            "wrong": "Otwierasz drzwi!",
            "right": " ✅ <span class="font-mono">Otwórz drzwi!</span>"
        }
    ]
}

{
    "title": "10. Ćwicz",
    "select_title": "Ćwiczenie 1. Określ rodzaj wyroku",
    "select_intro": "Określ, do jakiego typu należy zdanie.",
    "selects": [
        {
            "label": "Pracuje w banku. (Twierdząca / Przecząca / Pytająca / Imperatywna)",
            "prompt": "Jaki typ?"
        },
        {
            "label": "Czy mówisz po angielsku? (Twierdząca / Przecząca / Pytająca / Imperatywna)",
            "prompt": "Jaki typ?"
        },
        {
            "label": "Zamknij okno. (Twierdząca / Przecząca / Pytająca / Imperatyw)",
            "prompt": "Jaki typ?"
        },
        {
            "label": "Nie rozumiem. (Twierdzące / Przeczące / Pytające / Imperatywne)",
            "prompt": "Co typ?"
        }
    ],
    "options": [
        "Twierdzący",
        "Przeczący",
        "Pytający",
        "Rozkazujący"
    ],
    "input_title": "Ćwiczenie 2. Przekształć zdanie",
    "input_intro": "Zamień zdanie twierdzące na inne typy.",
    "inputs": [
        {
            "before": "Lubi muzykę. → Negatywne:",
            "after": " →"
        },
        {
            "before": "Lubi muzykę. → Pytanie:",
            "after": " →"
        },
        {
            "before": "Jesteś cichy. → Imperatyw:",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Korekta błędu",
    "rephrase_intro": "Znajdź i popraw błąd w zdaniu.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Nie lubi kawa.",
            "example_target": "Ona nie lubi kawy."
        },
        {
            "original": "1. Czy lubi piłkę nożną?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Bądź cicho!",
            "placeholder": "Popraw błąd"
        }
    ]
}

